//! # zrame.wl — hand-written Wayland client bindings
//!
//! The thin FFI floor of zrame, in the same spirit as zicro's `gpu_wgpu_bridge_ffi`:
//! explicit `extern` declarations, no `@cImport`. Core `wl_*` interface tables come
//! from libwayland-client; xdg-shell / ext-background-effect / cursor-shape tables are
//! generated by `wayland-scanner private-code` in build.zig and linked in.
//!
//! Every request wrapper is the Zig spelling of the macro the C client headers would
//! have generated: one `wl_proxy_marshal_flags` call with the interface's opcode and
//! signature-ordered arguments. Events arrive through per-interface listener structs
//! (arrays of C function pointers, dispatched by libwayland against the same tables).

const std = @import("std");

// --- libwayland-client core -----------------------------------------------------------

pub const Proxy = opaque {};
pub const Display = opaque {};

pub const Interface = extern struct {
    name: [*:0]const u8,
    version: c_int,
    method_count: c_int,
    methods: ?[*]const Message,
    event_count: c_int,
    events: ?[*]const Message,
};

pub const Message = extern struct {
    name: [*:0]const u8,
    signature: [*:0]const u8,
    types: ?[*]const ?*const Interface,
};

pub const MARSHAL_FLAG_DESTROY: u32 = 1;

pub extern fn wl_display_connect(name: ?[*:0]const u8) ?*Display;
pub extern fn wl_display_disconnect(display: *Display) void;
pub extern fn wl_display_get_fd(display: *Display) c_int;
pub extern fn wl_display_roundtrip(display: *Display) c_int;
pub extern fn wl_display_flush(display: *Display) c_int;
pub extern fn wl_display_dispatch(display: *Display) c_int;
pub extern fn wl_display_dispatch_pending(display: *Display) c_int;
pub extern fn wl_display_prepare_read(display: *Display) c_int;
pub extern fn wl_display_read_events(display: *Display) c_int;
pub extern fn wl_display_cancel_read(display: *Display) void;
pub extern fn wl_display_get_error(display: *Display) c_int;

pub extern fn wl_proxy_marshal_flags(
    proxy: *Proxy,
    opcode: u32,
    interface: ?*const Interface,
    version: u32,
    flags: u32,
    ...
) ?*Proxy;
pub extern fn wl_proxy_add_listener(
    proxy: *Proxy,
    implementation: [*]const ?*const fn () callconv(.c) void,
    data: ?*anyopaque,
) c_int;
pub extern fn wl_proxy_get_version(proxy: *Proxy) u32;
pub extern fn wl_proxy_destroy(proxy: *Proxy) void;

// Interface tables. `wl_*` are exported by libwayland-client.so; the rest are compiled
// from wayland-scanner output in build.zig.
pub extern const wl_registry_interface: Interface;
pub extern const wl_callback_interface: Interface;
pub extern const wl_compositor_interface: Interface;
pub extern const wl_surface_interface: Interface;
pub extern const wl_region_interface: Interface;
pub extern const wl_shm_interface: Interface;
pub extern const wl_shm_pool_interface: Interface;
pub extern const wl_buffer_interface: Interface;
pub extern const wl_seat_interface: Interface;
pub extern const wl_pointer_interface: Interface;
pub extern const wl_keyboard_interface: Interface;
pub extern const xdg_wm_base_interface: Interface;
pub extern const xdg_surface_interface: Interface;
pub extern const xdg_toplevel_interface: Interface;
pub extern const ext_background_effect_manager_v1_interface: Interface;
pub extern const ext_background_effect_surface_v1_interface: Interface;
pub extern const wp_cursor_shape_manager_v1_interface: Interface;
pub extern const wp_cursor_shape_device_v1_interface: Interface;

/// 24.8 fixed point, the wire format of pointer coordinates.
pub const Fixed = i32;

pub fn fixedToF64(f: Fixed) f64 {
    return @as(f64, @floatFromInt(f)) / 256.0;
}

fn proxy(ptr: anytype) *Proxy {
    return @ptrCast(ptr);
}

fn version(ptr: anytype) u32 {
    return wl_proxy_get_version(@ptrCast(ptr));
}

fn addListener(ptr: anytype, listener: anytype, data: ?*anyopaque) void {
    // `listener` is a pointer to an extern struct of C fn pointers — exactly the
    // implementation array libwayland indexes by opcode.
    _ = wl_proxy_add_listener(@ptrCast(ptr), @ptrCast(@alignCast(listener)), data);
}

// --- wl_display / wl_registry / wl_callback -------------------------------------------

pub const Registry = opaque {
    pub const Listener = extern struct {
        global: *const fn (data: ?*anyopaque, registry: *Registry, name: u32, interface: [*:0]const u8, ver: u32) callconv(.c) void,
        global_remove: *const fn (data: ?*anyopaque, registry: *Registry, name: u32) callconv(.c) void,
    };

    pub fn setListener(self: *Registry, listener: *const Listener, data: ?*anyopaque) void {
        addListener(self, listener, data);
    }

    /// `wl_registry.bind` — signature "usun": the interface name and version travel
    /// with the new_id because the XML leaves the new object's type open.
    pub fn bind(self: *Registry, name: u32, interface: *const Interface, ver: u32) ?*Proxy {
        return wl_proxy_marshal_flags(proxy(self), 0, interface, ver, 0, name, interface.name, ver, @as(?*Proxy, null));
    }
};

pub fn displayGetRegistry(display: *Display) *Registry {
    const p = wl_proxy_marshal_flags(@ptrCast(display), 1, &wl_registry_interface, 1, 0, @as(?*Proxy, null));
    return @ptrCast(p.?);
}

pub const Callback = opaque {
    pub const Listener = extern struct {
        done: *const fn (data: ?*anyopaque, callback: *Callback, callback_data: u32) callconv(.c) void,
    };

    pub fn setListener(self: *Callback, listener: *const Listener, data: ?*anyopaque) void {
        addListener(self, listener, data);
    }

    pub fn destroy(self: *Callback) void {
        wl_proxy_destroy(proxy(self));
    }
};

// --- wl_compositor / wl_surface / wl_region -------------------------------------------

pub const Compositor = opaque {
    pub fn createSurface(self: *Compositor) *Surface {
        const p = wl_proxy_marshal_flags(proxy(self), 0, &wl_surface_interface, version(self), 0, @as(?*Proxy, null));
        return @ptrCast(p.?);
    }

    pub fn createRegion(self: *Compositor) *Region {
        const p = wl_proxy_marshal_flags(proxy(self), 1, &wl_region_interface, version(self), 0, @as(?*Proxy, null));
        return @ptrCast(p.?);
    }
};

pub const Surface = opaque {
    pub fn destroy(self: *Surface) void {
        _ = wl_proxy_marshal_flags(proxy(self), 0, null, version(self), MARSHAL_FLAG_DESTROY);
    }

    pub fn attach(self: *Surface, buffer: ?*Buffer, x: i32, y: i32) void {
        _ = wl_proxy_marshal_flags(proxy(self), 1, null, version(self), 0, @as(?*Proxy, @ptrCast(buffer)), x, y);
    }

    pub fn frame(self: *Surface) *Callback {
        const p = wl_proxy_marshal_flags(proxy(self), 3, &wl_callback_interface, version(self), 0, @as(?*Proxy, null));
        return @ptrCast(p.?);
    }

    pub fn setOpaqueRegion(self: *Surface, region: ?*Region) void {
        _ = wl_proxy_marshal_flags(proxy(self), 4, null, version(self), 0, @as(?*Proxy, @ptrCast(region)));
    }

    pub fn setInputRegion(self: *Surface, region: ?*Region) void {
        _ = wl_proxy_marshal_flags(proxy(self), 5, null, version(self), 0, @as(?*Proxy, @ptrCast(region)));
    }

    pub fn commit(self: *Surface) void {
        _ = wl_proxy_marshal_flags(proxy(self), 6, null, version(self), 0);
    }

    pub fn damageBuffer(self: *Surface, x: i32, y: i32, w: i32, h: i32) void {
        _ = wl_proxy_marshal_flags(proxy(self), 9, null, version(self), 0, x, y, w, h);
    }
};

pub const Region = opaque {
    pub fn destroy(self: *Region) void {
        _ = wl_proxy_marshal_flags(proxy(self), 0, null, version(self), MARSHAL_FLAG_DESTROY);
    }

    pub fn add(self: *Region, x: i32, y: i32, w: i32, h: i32) void {
        _ = wl_proxy_marshal_flags(proxy(self), 1, null, version(self), 0, x, y, w, h);
    }
};

// --- wl_shm / wl_shm_pool / wl_buffer --------------------------------------------------

pub const SHM_FORMAT_ARGB8888: u32 = 0;

pub const Shm = opaque {
    pub fn createPool(self: *Shm, fd: c_int, size: i32) *ShmPool {
        const p = wl_proxy_marshal_flags(proxy(self), 0, &wl_shm_pool_interface, version(self), 0, @as(?*Proxy, null), fd, size);
        return @ptrCast(p.?);
    }
};

pub const ShmPool = opaque {
    pub fn createBuffer(self: *ShmPool, offset: i32, w: i32, h: i32, stride: i32, format: u32) *Buffer {
        const p = wl_proxy_marshal_flags(proxy(self), 0, &wl_buffer_interface, version(self), 0, @as(?*Proxy, null), offset, w, h, stride, format);
        return @ptrCast(p.?);
    }

    pub fn destroy(self: *ShmPool) void {
        _ = wl_proxy_marshal_flags(proxy(self), 1, null, version(self), MARSHAL_FLAG_DESTROY);
    }
};

pub const Buffer = opaque {
    pub const Listener = extern struct {
        release: *const fn (data: ?*anyopaque, buffer: *Buffer) callconv(.c) void,
    };

    pub fn setListener(self: *Buffer, listener: *const Listener, data: ?*anyopaque) void {
        addListener(self, listener, data);
    }

    pub fn destroy(self: *Buffer) void {
        _ = wl_proxy_marshal_flags(proxy(self), 0, null, version(self), MARSHAL_FLAG_DESTROY);
    }
};

// --- wl_seat / wl_pointer ---------------------------------------------------------------

pub const SEAT_CAPABILITY_POINTER: u32 = 1;
pub const SEAT_CAPABILITY_KEYBOARD: u32 = 2;
pub const BTN_LEFT: u32 = 0x110;
pub const POINTER_BUTTON_STATE_PRESSED: u32 = 1;
pub const KEY_ESC: u32 = 1; // linux evdev keycode
pub const KEYBOARD_KEY_STATE_PRESSED: u32 = 1;

pub const Seat = opaque {
    pub const Listener = extern struct {
        capabilities: *const fn (data: ?*anyopaque, seat: *Seat, capabilities: u32) callconv(.c) void,
        name: *const fn (data: ?*anyopaque, seat: *Seat, name: [*:0]const u8) callconv(.c) void,
    };

    pub fn setListener(self: *Seat, listener: *const Listener, data: ?*anyopaque) void {
        addListener(self, listener, data);
    }

    pub fn getPointer(self: *Seat) *Pointer {
        const p = wl_proxy_marshal_flags(proxy(self), 0, &wl_pointer_interface, version(self), 0, @as(?*Proxy, null));
        return @ptrCast(p.?);
    }

    pub fn getKeyboard(self: *Seat) *Keyboard {
        const p = wl_proxy_marshal_flags(proxy(self), 1, &wl_keyboard_interface, version(self), 0, @as(?*Proxy, null));
        return @ptrCast(p.?);
    }
};

pub const Pointer = opaque {
    /// The full wl_pointer event set; entries past the bound version are never invoked.
    pub const Listener = extern struct {
        enter: *const fn (data: ?*anyopaque, pointer: *Pointer, serial: u32, surface: ?*Surface, sx: Fixed, sy: Fixed) callconv(.c) void,
        leave: *const fn (data: ?*anyopaque, pointer: *Pointer, serial: u32, surface: ?*Surface) callconv(.c) void,
        motion: *const fn (data: ?*anyopaque, pointer: *Pointer, time: u32, sx: Fixed, sy: Fixed) callconv(.c) void,
        button: *const fn (data: ?*anyopaque, pointer: *Pointer, serial: u32, time: u32, button: u32, state: u32) callconv(.c) void,
        axis: *const fn (data: ?*anyopaque, pointer: *Pointer, time: u32, axis: u32, value: Fixed) callconv(.c) void,
        frame: *const fn (data: ?*anyopaque, pointer: *Pointer) callconv(.c) void,
        axis_source: *const fn (data: ?*anyopaque, pointer: *Pointer, axis_source: u32) callconv(.c) void,
        axis_stop: *const fn (data: ?*anyopaque, pointer: *Pointer, time: u32, axis: u32) callconv(.c) void,
        axis_discrete: *const fn (data: ?*anyopaque, pointer: *Pointer, axis: u32, discrete: i32) callconv(.c) void,
        axis_value120: *const fn (data: ?*anyopaque, pointer: *Pointer, axis: u32, value120: i32) callconv(.c) void,
        axis_relative_direction: *const fn (data: ?*anyopaque, pointer: *Pointer, axis: u32, direction: u32) callconv(.c) void,
    };

    pub fn setListener(self: *Pointer, listener: *const Listener, data: ?*anyopaque) void {
        addListener(self, listener, data);
    }
};

pub const Keyboard = opaque {
    pub const Listener = extern struct {
        /// Carries an mmap-able fd the listener must close (we read keys as raw evdev
        /// codes, so the xkb keymap itself goes unused).
        keymap: *const fn (data: ?*anyopaque, keyboard: *Keyboard, format: u32, fd: i32, size: u32) callconv(.c) void,
        enter: *const fn (data: ?*anyopaque, keyboard: *Keyboard, serial: u32, surface: ?*Surface, keys: ?*anyopaque) callconv(.c) void,
        leave: *const fn (data: ?*anyopaque, keyboard: *Keyboard, serial: u32, surface: ?*Surface) callconv(.c) void,
        key: *const fn (data: ?*anyopaque, keyboard: *Keyboard, serial: u32, time: u32, key: u32, state: u32) callconv(.c) void,
        modifiers: *const fn (data: ?*anyopaque, keyboard: *Keyboard, serial: u32, depressed: u32, latched: u32, locked: u32, group: u32) callconv(.c) void,
        repeat_info: *const fn (data: ?*anyopaque, keyboard: *Keyboard, rate: i32, delay: i32) callconv(.c) void,
    };

    pub fn setListener(self: *Keyboard, listener: *const Listener, data: ?*anyopaque) void {
        addListener(self, listener, data);
    }
};

